public DocumentType(String name, String publicId, String systemId, String baseUri) {
    super(baseUri);

    Validate.notNull(name);
    attr("name", name);
    attr("publicId", publicId);
    attr("systemId", systemId);
}

additional_testcases.testcase:
@Test
public void constructorAcceptsWhitespaceOnlyName() {
    DocumentType docType = new DocumentType("   ", "", "", "");
    assertEquals("   ", docType.attr("name"));
}

@Test(expected = IllegalArgumentException.class)
public void constructorRejectsNullName() {
    DocumentType fail = new DocumentType(null, "", "", "");
}

@Test
public void handlesDoctypeWithWhitespace() {
    Document doc = Jsoup.parse("<!DOCTYPE   >");
    assertEquals("<!DOCTYPE> <html> <head></head> <body></body> </html>",
                 StringUtil.normaliseWhitespace(doc.outerHtml()));
}
